from __future__ import annotations
from dataclasses import dataclass, field
from enum import Enum
from typing import Any, Optional

class SLATermType(Enum):
    FRESHNESS         = "freshness"
    COMPLETENESS      = "completeness"
    NULL_RATE         = "null_rate"
    DUPLICATE_RATE    = "duplicate_rate"
    INGESTION_LATENCY = "ingestion_latency"
    BREACH_NOTIFY     = "breach_notification"

@dataclass
class SLATerm:
    term_type: SLATermType
    threshold: float      # the contractual limit
    unit: str             # "hours", "ratio", "minutes"
    percentile: Optional[int] = None  # e.g. 95 for p95 latency

@dataclass
class SLAViolation:
    term: SLATerm
    actual: float
    breach_at: str        # ISO timestamp
    contract_id: str

    @property
    def severity(self) -> str:
        ratio = self.actual / max(self.term.threshold, 1e-9)
        if ratio > 5:
            return "P1"
        elif ratio > 2:
            return "P2"
        return "P3"

@dataclass
class SLAMonitorResult:
    contract_id: str
    checked_at: str
    violations: list[SLAViolation] = field(default_factory=list)

    @property
    def healthy(self) -> bool:
        return len(self.violations) == 0
